package com.lifepulse.notification;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;import com.baomidou.mybatisplus.core.conditions.update.LambdaUpdateWrapper;import com.lifepulse.common.IdGenerator;import com.lifepulse.entity.NotifyTask;import com.lifepulse.mapper.NotifyTaskMapper;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Service;import org.slf4j.Logger;import org.slf4j.LoggerFactory;import java.time.LocalDateTime;import java.util.List;
@Service public class NotifyTaskService {private static final Logger log=LoggerFactory.getLogger(NotifyTaskService.class);private final NotifyTaskMapper mapper;private final NotificationService notifications;private final IdGenerator ids;public NotifyTaskService(NotifyTaskMapper m,NotificationService n,IdGenerator i){mapper=m;notifications=n;ids=i;}public void notify(Long u,String title,String content,String type){enqueue(u,title,content,type);}public void enqueue(Long u,String title,String content,String type){LocalDateTime now=LocalDateTime.now();NotifyTask t=new NotifyTask();t.setId(ids.nextId());t.setUserId(u);t.setTitle(title);t.setContent(content);t.setType(type);t.setStatus("PENDING");t.setRetryCount(0);t.setNextRetryTime(now);t.setCreatedAt(now);t.setUpdatedAt(now);mapper.insert(t);log.info("notify_task_enqueued taskId={} userId={} type={}",t.getId(),u,type);}@Scheduled(fixedDelay=3000)public void dispatch(){List<NotifyTask> tasks=mapper.selectList(new LambdaQueryWrapper<NotifyTask>().eq(NotifyTask::getStatus,"PENDING").le(NotifyTask::getNextRetryTime,LocalDateTime.now()).last("limit 50"));for(NotifyTask t:tasks){try{notifications.notify(t.getUserId(),t.getTitle(),t.getContent(),t.getType());mapper.update(null,new LambdaUpdateWrapper<NotifyTask>().eq(NotifyTask::getId,t.getId()).set(NotifyTask::getStatus,"SENT").set(NotifyTask::getUpdatedAt,LocalDateTime.now()));log.info("notify_task_sent taskId={} userId={} type={}",t.getId(),t.getUserId(),t.getType());}catch(Exception e){mapper.update(null,new LambdaUpdateWrapper<NotifyTask>().eq(NotifyTask::getId,t.getId()).setSql("retry_count = retry_count + 1").set(NotifyTask::getNextRetryTime,LocalDateTime.now().plusSeconds(10)).set(NotifyTask::getUpdatedAt,LocalDateTime.now()));log.warn("notify_task_retry taskId={} userId={} error={}",t.getId(),t.getUserId(),e.getMessage());}}}}
